prompt --application/pages/page_00001
begin
wwv_flow_imp_page.create_page(
 p_id=>1
,p_name=>'Home'
,p_alias=>'HOME'
,p_step_title=>'Apex Debug helper'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'document.querySelectorAll(''.f1-error-badge'').forEach(badge => {',
'    const count = parseInt(badge.getAttribute(''data-errors'')) || 0;',
'    badge.style.cssText = `',
'        color: #fff;',
'        background: ${count > 0 ? ''#E8002D'' : ''#4CAF50''};',
'        padding: 2px 8px;',
'        border-radius: 10px;',
'        font-weight: 700;',
'        display: inline-block;',
'    `;',
'});'))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'13'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(259268498293686382)
,p_plug_name=>'Debug Sessions List'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    PAGE_VIEW_ID,',
'    APPLICATION_ID,',
'    PAGE_ID,',
'    APEX_USER,',
'    MIN(MESSAGE_TIMESTAMP) AS SESSION_START,',
'    ROUND(MAX(ELAPSED_TIME), 3) AS DURATION_SECONDS,',
'    COUNT(*) AS MESSAGE_COUNT,',
'    SUM(CASE WHEN MESSAGE_LEVEL = 1 THEN 1 ELSE 0 END) AS ERROR_COUNT,',
'    MAX(EXECUTION_TIME) AS SLOWEST_OPERATION_MS',
'FROM apex_debug_messages',
'WHERE APEX_USER NOT IN (''-'', ''nobody'')',
'AND APEX_USER IS NOT NULL',
'GROUP BY PAGE_VIEW_ID, APPLICATION_ID, PAGE_ID, APEX_USER',
'ORDER BY MIN(MESSAGE_TIMESTAMP) DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
