prompt --application/pages/page_00003
begin
wwv_flow_imp_page.create_page(
 p_id=>3
,p_name=>'Performance View'
,p_alias=>'PERFORMANCE-VIEW'
,p_step_title=>'Performance View'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'// Colour execution times',
'document.querySelectorAll(''.perf-exec-time'').forEach(cell => {',
'    const ms = parseFloat(cell.getAttribute(''data-ms'')) || 0;',
'    if (ms > 0.5) {',
'        cell.style.cssText = ''color:#E8002D; font-weight:700; font-family:monospace;'';',
'    } else if (ms > 0.1) {',
'        cell.style.cssText = ''color:#FF9800; font-weight:700; font-family:monospace;'';',
'    } else {',
'        cell.style.cssText = ''color:#4CAF50; font-family:monospace;'';',
'    }',
'});',
'',
'// Colour operation types',
'const opColors = {',
'    ''Session State'':  ''#2196F3'',',
'    ''Item Fetch'':     ''#2196F3'',',
'    ''Commit'':         ''#E8002D'',',
'    ''Plugin Load'':    ''#9C27B0'',',
'    ''Page Render'':    ''#009688'',',
'    ''Region Render'':  ''#009688'',',
'    ''Memory Profile'': ''#FF9800'',',
'    ''Session Stats'':  ''#FF9800'',',
'    ''Security Check'': ''#F44336'',',
'    ''Internal'':       ''#9E9E9E''',
'};',
'',
'document.querySelectorAll(''.perf-op-type'').forEach(badge => {',
'    const type = badge.getAttribute(''data-type'');',
'    badge.style.cssText = `',
'        background: ${opColors[type] || ''#9E9E9E''};',
'        color: #fff;',
'        padding: 2px 8px;',
'        border-radius: 10px;',
'        font-size: 0.75rem;',
'        font-weight: 700;',
'        display: inline-block;',
'    `;',
'});'))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'.perf-exec-time {',
'    font-family: monospace;',
'    font-weight: 700;',
'}'))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'18'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(172529005537987658)
,p_plug_name=>'Performance View'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    PAGE_VIEW_ID,',
'    APPLICATION_ID,',
'    PAGE_ID,',
'    MESSAGE_TIMESTAMP,',
'    ROUND(EXECUTION_TIME, 4) AS EXEC_MS,',
'    CASE',
'        WHEN MESSAGE LIKE ''Session State:%'' THEN ''Session State''',
'        WHEN MESSAGE LIKE ''fetch_t_value%'' THEN ''Item Fetch''',
'        WHEN MESSAGE LIKE ''do_commit%'' THEN ''Commit''',
'        WHEN MESSAGE LIKE ''do_get_plugin%'' THEN ''Plugin Load''',
'        WHEN MESSAGE LIKE ''render_page_slot%'' THEN ''Page Render''',
'        WHEN MESSAGE LIKE ''render_region_slot%'' THEN ''Region Render''',
'        WHEN MESSAGE LIKE ''Evaluate which%'' THEN ''Component Eval''',
'        WHEN MESSAGE LIKE ''get_page_info%'' THEN ''Page Info''',
'        WHEN MESSAGE LIKE ''set_g_page_slots%'' THEN ''Page Slots''',
'        WHEN MESSAGE LIKE ''Memory Usage%'' THEN ''Memory Profile''',
'        WHEN MESSAGE LIKE ''Session Statistics%'' THEN ''Session Stats''',
'        WHEN MESSAGE LIKE ''rejoin_existing%'' THEN ''Session Rejoin''',
'        WHEN MESSAGE LIKE ''check session%'' THEN ''Security Check''',
'        WHEN MESSAGE LIKE ''add_header%'' THEN ''HTTP Header''',
'        ELSE ''Internal''',
'    END AS OPERATION_TYPE,',
'    SUBSTR(MESSAGE, 1, 200) AS MESSAGE_SHORT,',
'    APEX_USER',
'FROM apex_debug_messages',
'WHERE APEX_USER NOT IN (''-'', ''nobody'')',
'AND EXECUTION_TIME > 0',
'ORDER BY EXECUTION_TIME DESC',
'FETCH FIRST 200 ROWS ONLY'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
,p_prn_height=>8.5
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
