begin
wwv_flow_imp_page.create_page(
 p_id=>4
,p_name=>'Session State Trace'
,p_alias=>'SESSION-STATE-TRACE'
,p_step_title=>'Session State Trace'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'// Colour state operation badges',
'const stateColors = {',
'    ''State Fetch'': ''#2196F3'',',
'    ''State Save'':  ''#4CAF50'',',
'    ''State Clear'': ''#FF9800'',',
'    ''Item Detail'': ''#9C27B0'',',
'    ''Item Fetch'':  ''#009688'',',
'    ''Other'':       ''#9E9E9E''',
'};',
'',
'document.querySelectorAll(''.state-op-badge'').forEach(badge => {',
'    const op = badge.getAttribute(''data-op'');',
'    badge.style.cssText = `',
'        background: ${stateColors[op] || ''#9E9E9E''};',
'        color: #fff;',
'        padding: 2px 8px;',
'        border-radius: 10px;',
'        font-size: 0.75rem;',
'        font-weight: 700;',
'        display: inline-block;',
'    `;',
'});',
'',
'// Highlight protected values',
'document.querySelectorAll(''.state-item-value'').forEach(cell => {',
'    const val = cell.getAttribute(''data-val'');',
'    if (val === ''***'') {',
'        cell.style.cssText = ''color:#9E9E9E; font-style:italic;'';',
'        cell.innerText = ''*** protected'';',
'    } else if (val && val.length > 0) {',
'        cell.style.cssText = ''color:#4CAF50; font-family:monospace; font-weight:700;'';',
'    }',
'});'))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'.state-op-badge {',
'    white-space: nowrap;',
'}'))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'18'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(173609078163711821)
,p_plug_name=>'Session State Interactive Report'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>40
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    MESSAGE_TIMESTAMP,',
'    ROUND(EXECUTION_TIME, 4) AS EXEC_MS,',
'    ROUND(ELAPSED_TIME, 4) AS ELAPSED_S,',
'    -- Classify the message type',
'    CASE',
'        WHEN MESSAGE LIKE ''Session State: fetch%'' THEN ''State Fetch''',
'        WHEN MESSAGE LIKE ''Session State: save%'' THEN ''State Save''',
'        WHEN MESSAGE LIKE ''Session State: clear%'' THEN ''State Clear''',
'        WHEN MESSAGE LIKE ''... id=%'' THEN ''Item Detail''',
'        WHEN MESSAGE LIKE ''fetch_t_value%'' THEN ''Item Fetch''',
'        ELSE ''Other''',
'    END AS STATE_OPERATION,',
'    -- Extract item name from "... id=xxx, name=ITEM_NAME, type=..."',
'    CASE',
'    WHEN MESSAGE LIKE ''... id=%''',
'    THEN REGEXP_SUBSTR(MESSAGE, ''name=([^,]+)'', 1, 1, NULL, 1)',
'    WHEN MESSAGE LIKE ''fetch_t_value%''',
'    THEN COALESCE(',
'        NULLIF(REGEXP_SUBSTR(MESSAGE, ''p_item\.name=>([^,]+)'', 1, 1, NULL, 1), ''''),',
'        ''(id='' || REGEXP_SUBSTR(MESSAGE, ''p_item_id=>([^,]+)'', 1, 1, NULL, 1) || '')''',
'    )',
'    ELSE NULL',
'END AS ITEM_NAME,',
'    -- Extract item type',
'    CASE',
'        WHEN MESSAGE LIKE ''... id=%''',
'        THEN REGEXP_SUBSTR(MESSAGE, ''type=([^,]+)'', 1, 1, NULL, 1)',
'        ELSE NULL',
'    END AS ITEM_TYPE,',
unistr('    -- Extract value \2014 shows *** for protected items'),
'    CASE',
'        WHEN MESSAGE LIKE ''... id=%''',
'        THEN REGEXP_SUBSTR(MESSAGE, ''value=(.+)$'', 1, 1, NULL, 1)',
'        ELSE NULL',
'    END AS ITEM_VALUE,',
'    MESSAGE AS FULL_MESSAGE',
'FROM apex_debug_messages',
'WHERE PAGE_VIEW_ID = :P4_PAGE_VIEW_ID',
'AND (',
'    MESSAGE LIKE ''Session State:%''',
'    OR MESSAGE LIKE ''... id=%''',
'    OR MESSAGE LIKE ''fetch_t_value%''',
')',
'AND (',
'    :P4_FILTER = ''ALL''',
'    OR (:P4_FILTER = ''FETCH'' AND MESSAGE LIKE ''... id=%'')',
'    OR (:P4_FILTER = ''OPS'' AND MESSAGE LIKE ''Session State:%'')',
')',
'ORDER BY MESSAGE_TIMESTAMP ASC'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
